/**
 * Create Task form — pick project + workflow, enter title + description.
 *
 * Task ID is auto-generated by the store based on the project's prefix and
 * the workflow letter (e.g. DA-017F). We preview the NEXT id by fetching
 * the current task list and finding the max number for this prefix.
 */
import { useEffect, useMemo, useState } from "react";
import { Modal } from "./Modal";
import { useProjects } from "../hooks/useProjects";
import { useWorkflows } from "../hooks/useWorkflows";
import { useTasks } from "../hooks/useTasks";
import { useRoute } from "../router";
import { publish } from "../hooks/data-bus";
import { effectiveLanes } from "../../../shared/models";

export function CreateTaskForm({
  open,
  onClose,
}: {
  open: boolean;
  onClose: () => void;
}): JSX.Element {
  const { projects } = useProjects();
  const { workflows } = useWorkflows();
  const { tasks, refresh: refreshTasks } = useTasks();
  const { selectedProjectId } = useRoute();

  const [projectId, setProjectId] = useState<string>("");
  const [workflow, setWorkflow] = useState<string>("F");
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [kind, setKind] = useState<"single" | "campaign">("single");
  // One item per line for campaigns. Blank lines ignored. Each becomes
  // a CampaignItem with description + auto-generated id.
  const [itemsText, setItemsText] = useState("");
  const [error, setError] = useState<string>("");
  const [saving, setSaving] = useState(false);

  // Default project: the one currently being viewed (selectedProjectId from
  // the router). Falls back to the first project only when nothing is
  // selected — prevents silently assigning tasks to whichever project
  // sorts alphabetically first while the user has a different one open.
  useEffect(() => {
    if (!open) return;
    if (projectId) return;
    if (projects.length === 0) return;
    const preferred =
      selectedProjectId && projects.find((p) => p.id === selectedProjectId)
        ? selectedProjectId
        : projects[0]!.id;
    setProjectId(preferred);
  }, [open, projectId, projects, selectedProjectId]);

  // Reset project each time the modal opens so switching views
  // between opens honors the new selectedProjectId.
  useEffect(() => {
    if (!open) setProjectId("");
  }, [open]);

  const activeProject = projects.find((p) => p.id === projectId);

  /** Best-effort next ID preview — same algorithm as TaskStore.nextTaskId(). */
  const nextIdPreview = useMemo<string>(() => {
    if (!activeProject) return "—";
    const prefix = activeProject.prefix;
    const re = new RegExp(`^${prefix}-(\\d{3,})([A-Z])$`);
    let maxN = 0;
    for (const t of tasks) {
      const m = re.exec(t.id);
      if (m) maxN = Math.max(maxN, Number.parseInt(m[1]!, 10));
    }
    const nnn = String(maxN + 1).padStart(3, "0");
    return `${prefix}-${nnn}${workflow}`;
  }, [activeProject, tasks, workflow]);

  const reset = (): void => {
    setTitle("");
    setDescription("");
    setError("");
    setSaving(false);
  };

  const close = (): void => {
    reset();
    onClose();
  };

  async function onSubmit(e: React.FormEvent): Promise<void> {
    e.preventDefault();
    setError("");

    if (!activeProject) return setError("Select a project");
    if (!title.trim()) return setError("Title is required");

    try {
      setSaving(true);
      if (!window.mc) {
        return setError("Not connected to main process — try `npm run dev`");
      }
      // Start the task in the first lane of the selected workflow. For
      // workflows that declare `lanes` in workflow.json (e.g. X-brainstorm)
      // this means new tasks land in the right first step instead of the
      // schema's "plan" default.
      const selectedWorkflow = workflows.find((w) => w.code === workflow);
      const startLane = effectiveLanes(selectedWorkflow)[0];

      const items = kind === "campaign"
        ? itemsText
            .split("\n")
            .map((line) => line.trim())
            .filter((line) => line.length > 0)
            .map((description, i) => ({
              // Post-filter index → contiguous IDs, no gaps from blank lines.
              // Width scales with count so item-1000 doesn't look like item-001.
              id: `item-${String(i + 1).padStart(4, "0")}`,
              description,
              status: "pending" as const,
              notes: "",
            }))
        : undefined;

      await window.mc.createTask({
        title: title.trim(),
        description,
        projectId: activeProject.id,
        projectPrefix: activeProject.prefix,
        workflow,
        kind,
        ...(startLane ? { lane: startLane } : {}),
        ...(items ? { items } : {}),
      });
      publish("tasks");
      await refreshTasks();
      close();
    } catch (err) {
      setError(err instanceof Error ? err.message : String(err));
    } finally {
      setSaving(false);
    }
  }

  return (
    <Modal open={open} title="+ Create Task" onClose={close}>
      <form onSubmit={onSubmit}>
        <style>{`
          .ctf input, .ctf select, .ctf textarea {
            background: var(--bg); color: var(--text);
            border: 1px solid var(--border); border-radius: 8px;
            padding: 9px 11px; font-family: inherit; font-size: 14px;
            width: 100%;
          }
          .ctf label { font-size: 12px; color: var(--muted); }
          .ctf .field { display: grid; gap: 4px; margin-bottom: 14px; }
          .ctf .hint { font-size: 11px; color: var(--muted); }
        `}</style>
        <div className="ctf">
          <div className="field">
            <label>Project</label>
            <select
              value={projectId}
              onChange={(e) => setProjectId(e.target.value)}
            >
              {projects.map((p) => (
                <option key={p.id} value={p.id}>
                  {p.name} ({p.prefix})
                </option>
              ))}
            </select>
          </div>
          <div className="field">
            <label>Workflow</label>
            <select
              value={workflow}
              onChange={(e) => setWorkflow(e.target.value)}
            >
              {workflows.map((w) => (
                <option key={w.code} value={w.code}>
                  {w.code} · {w.name} — {w.description || "(no description)"}
                </option>
              ))}
            </select>
            <div className="hint">Read from the <code>workflows/</code> folder at boot.</div>
          </div>
          <div className="field">
            <label>Kind</label>
            <select value={kind} onChange={(e) => setKind(e.target.value as "single" | "campaign")}>
              <option value="single">Single — one task × N cycles</option>
              <option value="campaign">Campaign — one task × N items (iterate each)</option>
            </select>
            <div className="hint">
              Campaigns process a list of items, one session per item. Runtime
              iteration is not wired yet — items show up for planning only.
            </div>
          </div>
          <div className="field">
            <label>Title</label>
            <input
              autoFocus
              type="text"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              placeholder="Short, imperative — e.g. Add task-linked diff registry"
            />
          </div>
          <div className="field">
            <label>Description</label>
            <textarea
              rows={4}
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="What does done look like? Any constraints the Planner should know?"
            />
          </div>
          {kind === "campaign" && (
            <div className="field">
              <label>Items (one per line)</label>
              <textarea
                rows={5}
                value={itemsText}
                onChange={(e) => setItemsText(e.target.value)}
                placeholder={"./src/lib/thing-a.dll\n./src/lib/thing-b.dll\n./src/lib/thing-c.dll"}
              />
              <div className="hint">
                Optional at creation — Planner can generate items as part of
                its run. One item per line, blank lines ignored.
              </div>
            </div>
          )}

          {error && (
            <div
              style={{
                color: "var(--bad)",
                background: "rgba(255,123,123,0.1)",
                border: "1px solid var(--bad)",
                borderRadius: 8,
                padding: "8px 10px",
                marginTop: 8,
                fontSize: 13,
              }}
            >
              {error}
            </div>
          )}

          <div
            style={{
              display: "flex",
              alignItems: "center",
              marginTop: 14,
              gap: 8,
            }}
          >
            <span className="muted" style={{ fontSize: 12 }}>
              Task ID will be: <strong>{nextIdPreview}</strong>
            </span>
            <div style={{ marginLeft: "auto", display: "flex", gap: 8 }}>
              <button type="button" className="button ghost" onClick={close}>
                Cancel
              </button>
              <button type="submit" className="button" disabled={saving}>
                {saving ? "Creating…" : "Create Task"}
              </button>
            </div>
          </div>
        </div>
      </form>
    </Modal>
  );
}
